  igIntro2:             { AZ: "Instagram hesabını Facebook fan səhifəsi ilə qoşun", EN: "Connect Instagram account with a Facebook fan page", TR: "Instagram hesabını bir Facebook hayran sayfasıyla bağlayın", RU: "Свяжите аккаунт Instagram со страницей Facebook" },
