  emailStep3:           { AZ: "Göndərən ünvanını təyin edin", EN: "Set sender address", TR: "Gönderen adresini ayarlayın", RU: "Укажите адрес отправителя" },
  emailMailboxIntro:    { AZ: "Digər provayderlərdən gələn emailləri avtomatik olaraq Inbox-a yönləndirin. Bütün gələn emailləri bilet kimi qəbul edin və Tickets qovluğundan idarə edin.", EN: "Automatically forward emails from other providers directly to the Inbox. Receive all your incoming emails as tickets, and manage them through the Tickets folder.", TR: "Diğer sağlayıcılardan gelen e-postaları doğrudan Gelen Kutusu'na otomatik olarak iletin. Gelen tüm e-postalarınızı bilet olarak alın ve Biletler klasöründen yönetin.", RU: "Автоматически пересылайте письма от других провайдеров прямо в Inbox. Получайте все входящие email как тикеты и управляйте ими через папку Tickets." },
  emailNoMailboxes:     { AZ: "Hələ heç bir poçt qutusu qoşulmayıb.", EN: "No mailboxes connected yet.", TR: "Henüz bağlı posta kutusu yok.", RU: "Почтовых ящиков пока нет." },
  emailMissing:         { AZ: "Email-də nəsə çatışmır?", EN: "Missing anything in Email?", TR: "Email'de eksik bir şey mi var?", RU: "Чего-то не хватает в Email?" },
  emailGiveFeedback:    { AZ: "Rəy bildirin",        EN: "Give feedback",     TR: "Geri bildirim verin", RU: "Оставить отзыв" },
  emailSenderIntro:     { AZ: "TODO domenindən bilet göndərməyə davam edin və ya kredibellikinizi artırmaq və çatdırılmanı yaxşılaşdırmaq üçün öz domeninizdən istifadəyə başlayın.", EN: "Keep sending tickets from TODO domain or start using your own domain to improve your credibility and increase the deliverability.", TR: "TODO alan adından bilet göndermeye devam edin veya güvenilirliğinizi artırmak ve teslim edilebilirliği yükseltmek için kendi alan adınızı kullanmaya başlayın.", RU: "Продолжайте отправлять тикеты с домена TODO или начните использовать собственный домен, чтобы повысить доверие и доставляемость." },
  emailDefault:         { AZ: "Standart",            EN: "Default",           TR: "Varsayılan",         RU: "По умолчанию" },
  emailNoDefaultSelected: { AZ: "Standart seçilməyib", EN: "No default selected", TR: "Varsayılan seçilmedi", RU: "Не выбрано по умолчанию" },
