  emailSenderType:      { AZ: "Göndərən tipi",       EN: "Sender type",       TR: "Gönderen tipi",      RU: "Тип отправителя" },
  emailNoSenderAddresses: { AZ: "Hələ göndərən ünvanı yoxdur. İlk göndərən ünvanınızı əlavə edin.", EN: "No sender addresses yet. Add your first sender address.", TR: "Henüz gönderen adresi yok. İlk gönderen adresinizi ekleyin.", RU: "Пока нет адресов отправителей. Добавьте первый адрес." },
  emailDomainsIntro:    { AZ: "Öz domeninizdən email göndərmək çatdırılma göstəricilərini yaxşılaşdırır və emaillərinizi daha peşəkar göstərir. Domeni təsdiqləyin və emaillərinizdən \"via chatbot.local\" yazısını silin.", EN: "Sending emails from your domain can help improve delivery rates, and make your emails look more professional. Verify your domain and remove \"via chatbot.local\" from your emails.", TR: "Kendi alan adınızdan e-posta göndermek teslimat oranlarını iyileştirir ve e-postalarınızı daha profesyonel gösterir. Alan adınızı doğrulayın ve e-postalarınızdan \"via chatbot.local\" ifadesini kaldırın.", RU: "Отправка писем с вашего домена улучшает доставляемость и делает письма более профессиональными. Подтвердите домен и удалите \"via chatbot.local\" из писем." },
  emailNoDomains:       { AZ: "Hələ heç bir domen əlavə etməmisiniz.", EN: "You haven't added any domain yet.", TR: "Henüz hiç alan adı eklemediniz.", RU: "Вы ещё не добавили ни одного домена." },
  emailBlockedIntro:    { AZ: "Bilet qəbul etməyəcəyiniz bloklanmış e-poçt ünvanlarının siyahısı.", EN: "List of blocked e-mails addresses from which you won't receive any tickets.", TR: "Hiç bilet almayacağınız engellenmiş e-posta adreslerinin listesi.", RU: "Список заблокированных email-адресов, с которых вы не будете получать тикеты." },
  emailLastUpdate:      { AZ: "Son yenilənmə",       EN: "Last update",       TR: "Son güncelleme",     RU: "Последнее обновление" },
