  emailBlockAnother:    { AZ: "Başqa e-poçt ünvanını blokla", EN: "Block another e-mail address", TR: "Başka bir e-posta adresini engelle", RU: "Заблокировать другой email-адрес" },
  emailHowToAddSender:  { AZ: "Göndərən ünvanını necə əlavə etmək olar", EN: "How to add sender address", TR: "Gönderen adresi nasıl eklenir", RU: "Как добавить адрес отправителя" },
