// Provided-language dictionary (flat {key: string}).
export function getAdminI18n(lang) {
  const l = ADMIN_LANGS.includes(lang) ? lang : DEFAULT_ADMIN_LANG;
  const out = {};
  for (const [key, variants] of Object.entries(MESSAGES)) {
    out[key] = variants[l] ?? variants.EN ?? variants.AZ ?? key;
  }
  return out;
}

// Flexible translator: (lang, key, fallback?) -> string
export function tr(lang, key, fallback) {
  const variants = MESSAGES[key];
  if (!variants) return fallback ?? key;
  const l = ADMIN_LANGS.includes(lang) ? lang : DEFAULT_ADMIN_LANG;
  return variants[l] ?? variants.EN ?? variants.AZ ?? fallback ?? key;
}

export default MESSAGES;
